"""Generate a STRhub Verified PDF attestation report.

Usage (called by verify.yml after report.py):
    python harness/generate_pdf.py --manifest tools/<tool>/manifest.yml

Reads:
    reports/<slug>.json   (written by harness/report.py)
    datasets/index.json   (optional — enriches Section 7)

Writes:
    reports/<slug>.pdf
"""
from __future__ import annotations
import argparse
import atexit
import base64
import datetime as dt
import io
import json
import os
import pathlib
import re
import sys
import tempfile

import yaml
from reportlab.lib import colors
from reportlab.lib.enums import TA_CENTER
from reportlab.lib.pagesizes import A4
from reportlab.lib.styles import ParagraphStyle
from reportlab.lib.units import mm
from reportlab.platypus import (
    HRFlowable, Image as RLImage, KeepTogether, PageBreak,
    Paragraph, SimpleDocTemplate, Spacer, Table, TableStyle,
)
from reportlab.pdfgen import canvas as pdfcanvas

# ── Palette ───────────────────────────────────────────────────────────────────
TEAL       = colors.HexColor("#00909c")
TEAL_LIGHT = colors.HexColor("#e0f4f5")
TEAL_MID   = colors.HexColor("#b3e0e4")
INK        = colors.HexColor("#3d3d3d")
GRAY       = colors.HexColor("#6b7280")
GRAY_LIGHT = colors.HexColor("#f7f8fa")
BORDER     = colors.HexColor("#e5e7eb")
WHITE      = colors.white
RED_SOFT   = colors.HexColor("#ef4444")

W, H = A4
ML = 22*mm; MR = 22*mm; MT = 20*mm; MB = 20*mm
CW = W - ML - MR
LOGO_TEXT_GAP       = 4 * mm
LOGO_TEXT_GAP_INNER = 2.5 * mm

# ── Embedded logo (PNG, base64) ───────────────────────────────────────────────
LOGO_B64 = ""

def _logo_temp_path() -> str:
    tmp = tempfile.NamedTemporaryFile(suffix=".png", delete=False)
    tmp.write(base64.b64decode(LOGO_B64))
    tmp.close()
    atexit.register(os.unlink, tmp.name)
    return tmp.name

_LOGO_PATH = _logo_temp_path()

# ── Gate ladder (display order) ───────────────────────────────────────────────
GATE_DISPLAY = [
    ("available", "Available",                   "The pinned public source exists"),
    ("installs",  "Installs",                    "The environment builds from source"),
    ("runs",      "Runs",                        "Executes end-to-end without crashing"),
    ("io",        "Expected IO",                 "Produces a non-empty file in the declared format"),
    ("content",   "Output Structure Validation", "Output structure matches expected genotype-bearing format"),
]

LEVEL_LABEL = {
    "none":      "Not verified",
    "available": "Available",
    "installs":  "Installs",
    "runs":      "Runs",
    "io":        "Runs + Expected IO",
    "content":   "Runs + Output Structure Validation",
}

PANEL_MAP = {
    "illumina-bam-hg38":   "Autosomal STR",
    "illumina-bam-hg38-y": "Y-STR",
    "ont-bam-hg38":        "Autosomal STR (ONT)",
    "illumina-str-fastq":  "STR / SNP panel",
}

# ── Style helpers ─────────────────────────────────────────────────────────────
def S(name, **kw):
    base = dict(fontName="Helvetica", fontSize=9, leading=13,
                textColor=INK, spaceAfter=0, spaceBefore=0)
    base.update(kw)
    return ParagraphStyle(name, **base)

ST = {
    "report_title":  S("rt", fontSize=13.5, fontName="Helvetica-Bold",
                        textColor=INK, leading=17, spaceAfter=8),
    "tool_name":     S("tn", fontSize=18, fontName="Helvetica-Bold",
                        textColor=INK, leading=22, spaceAfter=2),
    "tool_sub":      S("ts", fontSize=10, textColor=GRAY, leading=14),
    "meta_label":    S("ml", fontSize=8, textColor=GRAY, leading=12),
    "tbl_header":    S("th", fontSize=7.5, textColor=GRAY,
                        fontName="Helvetica-Bold", leading=11),
    "tbl_cell":      S("tc", fontSize=8.5, textColor=INK, leading=12),
    "gate_name":     S("gn", fontSize=8.5, textColor=INK,
                        fontName="Helvetica-Bold", leading=12),
    "gate_desc":     S("gd", fontSize=8.5, textColor=GRAY, leading=12),
    "locus_name":    S("ln", fontSize=8.5, textColor=INK,
                        fontName="Helvetica-Bold", leading=12),
    "body":          S("bd", fontSize=8.5, textColor=GRAY, leading=13),
    "appendix_title":S("at", fontSize=10, fontName="Helvetica-Bold",
                        textColor=INK, leading=14, spaceAfter=3),
    "mono":          S("mo", fontSize=7.5, fontName="Courier",
                        textColor=INK, leading=12),
}

def HR(color=BORDER, thickness=0.5, spaceB=4, spaceA=6):
    return HRFlowable(width="100%", thickness=thickness,
                      color=color, spaceAfter=spaceA, spaceBefore=spaceB)

def vspace(h_mm):
    return Spacer(1, h_mm * mm)

def link(url, text=None, color="#00909c"):
    label = text or url
    return f'<a href="{url}" color="{color}">{label}</a>'

def section_num(num, title):
    return Paragraph(
        f'<font name="Helvetica-Bold">{num}.  {title}</font>',
        S("sn", fontSize=10.5, textColor=TEAL, leading=15,
          spaceAfter=6, spaceBefore=10))

def section_title(title):
    return Paragraph(
        f'<font name="Helvetica-Bold">{title}</font>',
        S("st", fontSize=10.5, textColor=TEAL, leading=15,
          spaceAfter=6, spaceBefore=10))

def keep_section(title_el, *content_els):
    return KeepTogether([title_el, *content_els])

def kv_table(rows, col1=44*mm):
    tdata = [[Paragraph(k, ST["meta_label"]),
              Paragraph(v, ST["tbl_cell"])] for k, v in rows]
    tbl = Table(tdata, colWidths=[col1, CW - col1])
    tbl.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "TOP"),
        ("LEFTPADDING",   (0,0),(-1,-1), 0),
        ("RIGHTPADDING",  (0,0),(-1,-1), 0),
        ("TOPPADDING",    (0,0),(-1,-1), 4),
        ("BOTTOMPADDING", (0,0),(-1,-1), 4),
        ("LINEBELOW",     (0,0),(-1,-2), 0.3, BORDER),
    ]))
    return tbl

def boxed(content_list, bg=None, border_color=BORDER, pad=12):
    bg = bg or GRAY_LIGHT
    tbl = Table([[content_list]], colWidths=[CW])
    tbl.setStyle(TableStyle([
        ("BACKGROUND",    (0,0),(-1,-1), bg),
        ("BOX",           (0,0),(-1,-1), 0.5, border_color),
        ("TOPPADDING",    (0,0),(-1,-1), pad),
        ("BOTTOMPADDING", (0,0),(-1,-1), pad),
        ("LEFTPADDING",   (0,0),(-1,-1), 14),
        ("RIGHTPADDING",  (0,0),(-1,-1), 14),
    ]))
    return tbl

def pass_badge(ok=True):
    if ok:
        text = '<font name="Helvetica-Bold" size="7" color="#ffffff">PASS</font>'
        bg = TEAL
    else:
        text = '<font name="Helvetica-Bold" size="7" color="#9ca3af">—</font>'
        bg = GRAY_LIGHT
    b = Table([[Paragraph(text, S("pb", alignment=TA_CENTER, leading=9))]],
              colWidths=[14*mm], rowHeights=[12])
    b.setStyle(TableStyle([
        ("BACKGROUND",    (0,0),(-1,-1), bg),
        ("ROUNDEDCORNERS",[3]),
        ("ALIGN",         (0,0),(-1,-1), "CENTER"),
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("TOPPADDING",    (0,0),(-1,-1), 1),
        ("BOTTOMPADDING", (0,0),(-1,-1), 1),
    ]))
    return b

def logo_image(height):
    from PIL import Image as PILImage
    w, h = PILImage.open(_LOGO_PATH).size
    width = height * w / h
    return RLImage(_LOGO_PATH, width=width, height=height)

# ── Headers ───────────────────────────────────────────────────────────────────
def build_header_cover():
    title_leading = 20
    url_leading = 10
    header_line_gap = title_leading - 18
    text_block_h = title_leading + header_line_gap + url_leading

    title = Paragraph(
        '<font name="Helvetica-Bold" size="18" color="#3d3d3d">STRhub</font>'
        '<font name="Helvetica" size="18" color="#00909c"> Verified</font>',
        S("ht", leading=title_leading, spaceAfter=0))
    url = Paragraph(
        '<a href="https://strhub.app" color="#00909c">strhub.app</a>  ·  '
        '<a href="https://strhub.app/verified" color="#00909c">strhub.app/verified</a>',
        S("hu", fontSize=8, textColor=GRAY, leading=url_leading,
          spaceBefore=header_line_gap))

    logo_img = logo_image(text_block_h)
    logo_w = logo_img.drawWidth
    text_w = CW - logo_w
    right = Table([[title], [url]], colWidths=[text_w - LOGO_TEXT_GAP])
    right.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(-1,-1), 0),
        ("RIGHTPADDING",  (0,0),(-1,-1), 0),
        ("TOPPADDING",    (0,0),(-1,-1), 0),
        ("BOTTOMPADDING", (0,0),(-1,-1), 0),
    ]))
    outer = Table([[logo_img, right]], colWidths=[logo_w, text_w])
    outer.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(0,-1),  0),
        ("LEFTPADDING",   (1,0),(1,-1),  LOGO_TEXT_GAP),
        ("RIGHTPADDING",  (0,0),(-1,-1), 0),
        ("TOPPADDING",    (0,0),(-1,-1), 0),
        ("BOTTOMPADDING", (0,0),(-1,-1), 0),
    ]))
    return outer

def build_header_inner(cfg):
    logo_h = 25
    logo_img = logo_image(logo_h)
    logo_w = logo_img.drawWidth
    title = Paragraph(
        '<font name="Helvetica-Bold" size="11" color="#3d3d3d">STRhub</font>'
        '<font name="Helvetica" size="11" color="#00909c"> Verified</font>',
        S("iht", leading=14))
    sub = Paragraph(
        f"{cfg['tool_display']}  ·  Technical Reproducibility Validation Report  ·  {cfg['ver_date']}",
        S("ihs", fontSize=7.5, textColor=GRAY, leading=11))
    text_w = CW - logo_w
    right = Table([[title], [sub]], colWidths=[text_w - LOGO_TEXT_GAP_INNER])
    right.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(-1,-1), 0),
        ("TOPPADDING",    (0,0),(-1,-1), 1),
        ("BOTTOMPADDING", (0,0),(-1,-1), 1),
    ]))
    outer = Table([[logo_img, right]], colWidths=[logo_w, text_w])
    outer.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(0,-1),  0),
        ("LEFTPADDING",   (1,0),(1,-1),  LOGO_TEXT_GAP_INNER),
        ("RIGHTPADDING",  (0,0),(-1,-1), 0),
        ("TOPPADDING",    (0,0),(-1,-1), 0),
        ("BOTTOMPADDING", (0,0),(-1,-1), 0),
    ]))
    return outer

# ── Footer / numbered canvas ───────────────────────────────────────────────────
def _draw_footer(cnv, page_count, cfg):
    cnv.saveState()
    fy = MB - 8 * mm
    font, size = "Helvetica", 6.5
    cnv.setStrokeColor(BORDER)
    cnv.setLineWidth(0.5)
    cnv.line(ML, fy + 7 * mm, W - MR, fy + 7 * mm)
    right_text = (
        f"Verification date: {cfg['ver_date']}  ·  {cfg['tool_display']}  ·  "
        f"{cnv.getPageNumber()}/{page_count}")
    right_w = cnv.stringWidth(right_text, font, size)
    left_max = W - MR - right_w - ML - 8 * mm
    left_text = f"Auto-generated by STRhub Verified · strhub.app · {cfg['gen_date']}"
    cnv.setFont(font, size)
    if cnv.stringWidth(left_text, font, size) > left_max:
        left_text = f"STRhub Verified · strhub.app · {cfg['gen_date']}"
    cnv.setFillColor(GRAY)
    cnv.drawString(ML, fy + 3 * mm, left_text)
    cnv.setFillColor(TEAL)
    cnv.drawRightString(W - MR, fy + 3 * mm, right_text)
    cnv.restoreState()


def _make_canvas_class(cfg):
    class NumberedCanvas(pdfcanvas.Canvas):
        def __init__(self, *args, **kwargs):
            pdfcanvas.Canvas.__init__(self, *args, **kwargs)
            self._saved_page_states = []

        def showPage(self):
            self._saved_page_states.append(dict(self.__dict__))
            self._startPage()

        def save(self):
            total = len(self._saved_page_states)
            for state in self._saved_page_states:
                self.__dict__.update(state)
                _draw_footer(self, total, cfg)
                pdfcanvas.Canvas.showPage(self)
            pdfcanvas.Canvas.save(self)

    return NumberedCanvas

# ── Cover ─────────────────────────────────────────────────────────────────────
def build_cover(cfg):
    els = []
    els.append(build_header_cover())
    els.append(HR(TEAL, thickness=1.5, spaceB=10, spaceA=14))

    els.append(Paragraph("Technical Reproducibility Validation Report", ST["report_title"]))
    els.append(vspace(2))
    els.append(Paragraph(cfg["tool_name"], ST["tool_name"]))
    els.append(Paragraph(f"Version {cfg['tool_version']}", ST["tool_sub"]))
    if cfg.get("panel"):
        els.append(Paragraph(cfg["panel"], ST["tool_sub"]))
    els.append(vspace(5))
    els.append(HR(spaceB=4, spaceA=10))

    attest_label = LEVEL_LABEL.get(cfg["level"], "Not verified")
    meta_rows = [
        ("Verification date",  cfg["ver_date"]),
        ("Repository commit",  link(cfg["commit_url"], cfg["commit"])),
        ("Attestation level",  f'<font color="#00909c"><b>{attest_label}</b></font>'),
        ("Permalink",          link(cfg["permalink"]) if cfg.get("permalink") else "—"),
        ("STRhub",             link("https://strhub.app")),
    ]
    tdata = [[Paragraph(k, ST["meta_label"]),
              Paragraph(v, ST["tbl_cell"])] for k, v in meta_rows]
    mt = Table(tdata, colWidths=[44*mm, CW - 44*mm])
    mt.setStyle(TableStyle([
        ("VALIGN",       (0,0),(-1,-1), "TOP"),
        ("LEFTPADDING",  (0,0),(-1,-1), 0),
        ("RIGHTPADDING", (0,0),(-1,-1), 0),
        ("TOPPADDING",   (0,0),(-1,-1), 4),
        ("BOTTOMPADDING",(0,0),(-1,-1), 4),
        ("LINEBELOW",    (0,0),(-1,-2), 0.3, BORDER),
    ]))
    els.append(mt)
    els.append(HR(spaceB=10, spaceA=10))

    scope_text = (
        "Independent automated verification of reproducible execution — "
        "confirms the tool installs, runs end-to-end, and produces "
        "structurally valid output in a standardized environment.<br/><br/>"
        "This is <b>not</b> an analytical validation. Genotype accuracy, "
        "concordance, forensic suitability, and regulatory compliance "
        "are out of scope."
    )
    els.append(section_title("SCOPE OF THIS REPORT"))
    els.append(vspace(2))

    def col_block(items, title_col, label):
        dash_hex = f"#{GRAY.hexval()[2:]}"
        out = [Paragraph(label, S("bl", fontName="Helvetica-Bold",
                                   fontSize=8, textColor=title_col,
                                   leading=12, spaceAfter=6))]
        for item in items:
            out.append(Paragraph(
                f'<font color="{dash_hex}">–</font>  {item}',
                S("bi", fontSize=8.5, textColor=INK, leading=14,
                  leftIndent=8, spaceAfter=2)))
        return out

    v_col = col_block(
        ["Source available", "Installation successful",
         "End-to-end execution", "Output generated"],
        TEAL, "WHAT WAS VERIFIED")
    nv_col = col_block(
        ["Genotype accuracy", "Concordance",
         "Forensic validity", "Regulatory compliance"],
        GRAY, "NOT VERIFIED")

    half = CW / 2
    els.append(boxed([Paragraph(scope_text, ST["body"])]))
    els.append(vspace(3))
    verify_tbl = Table([[v_col, nv_col]], colWidths=[half, half])
    verify_tbl.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "TOP"),
        ("BACKGROUND",    (0,0),(0,0),   TEAL_LIGHT),
        ("BACKGROUND",    (1,0),(1,0),   GRAY_LIGHT),
        ("BOX",           (0,0),(0,0),   0.5, TEAL_MID),
        ("BOX",           (1,0),(1,0),   0.5, BORDER),
        ("TOPPADDING",    (0,0),(-1,-1), 12),
        ("BOTTOMPADDING", (0,0),(-1,-1), 12),
        ("LEFTPADDING",   (0,0),(-1,-1), 14),
        ("RIGHTPADDING",  (0,0),(-1,-1), 14),
    ]))
    els.append(verify_tbl)
    return els

# ── Body ──────────────────────────────────────────────────────────────────────
def build_body(cfg):
    els = []
    els.append(build_header_inner(cfg))
    els.append(HR(TEAL, thickness=1.2, spaceB=4, spaceA=8))

    # §1 Executive Summary
    attest_label = LEVEL_LABEL.get(cfg["level"], "Not verified")
    gates_dict = dict(cfg["gates"])
    n_pass = sum(1 for ok in gates_dict.values() if ok)
    n_total = len(gates_dict)
    els.append(section_num("1", "Executive Summary"))
    exec_rows = [
        ("PURPOSE",           "Verify that the tool installs, runs end-to-end, and produces structurally valid output."),
        ("RESULT",            f'<font color="#00909c"><b>{n_pass}/{n_total} gates passed — {attest_label}</b></font>'),
        ("ATTESTATION LEVEL", f'<font color="#00909c"><b>{attest_label}</b></font>'),
        ("SCOPE",             "Installation, execution, and output structure verification."),
        ("NOT EVALUATED",     "Genotype accuracy · Concordance · Forensic validity · Regulatory compliance"),
    ]
    tdata = [[Paragraph(k, ST["tbl_header"]),
              Paragraph(v, ST["tbl_cell"])] for k, v in exec_rows]
    et = Table(tdata, colWidths=[44*mm, CW - 44*mm])
    et.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(-1,-1), 10),
        ("RIGHTPADDING",  (0,0),(-1,-1), 10),
        ("TOPPADDING",    (0,0),(-1,-1), 6),
        ("BOTTOMPADDING", (0,0),(-1,-1), 6),
        ("ROWBACKGROUNDS",(0,0),(-1,-1), [WHITE, GRAY_LIGHT]),
        ("LINEBELOW",     (0,0),(-1,-2), 0.3, BORDER),
        ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
    ]))
    els.append(et)

    # §2 Metadata
    els.append(section_num("2", "Reproducibility Metadata"))
    ver_time = cfg.get("ver_time", "")
    meta_rows = [
        ("Tool",            cfg["tool_name"]),
        ("Version",         cfg["tool_version"]),
        ("Repository",      link(cfg["repo_url"])),
        ("Commit (pinned)", link(cfg["commit_url"], cfg["commit"])),
        ("Container OS",    cfg.get("container_os", "ubuntu-22.04")),
        ("Marker panel",    cfg.get("panel", "—")),
        ("Verified on",     (cfg["ver_date"] + ("  " + ver_time if ver_time else "")).strip()),
        ("CI run",          link(cfg["ci_run"]) if cfg.get("ci_run") else "—"),
    ]
    els.append(kv_table(meta_rows))

    # §3 Run command
    els.append(section_num("3", "Exact Run Command"))
    els.append(Paragraph(
        "The following command was executed verbatim in the CI environment. "
        "Replacing the BAM, reference, and BED paths with your own inputs "
        "reproduces the verified run.",
        ST["body"]))
    els.append(vspace(3))
    cmd_content = [Paragraph(line, ST["mono"]) for line in cfg.get("cmd_lines", ["# Command not available"])]
    cmd_box = Table([[cmd_content]], colWidths=[CW])
    cmd_box.setStyle(TableStyle([
        ("BACKGROUND",    (0,0),(-1,-1), WHITE),
        ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
        ("TOPPADDING",    (0,0),(-1,-1), 12),
        ("BOTTOMPADDING", (0,0),(-1,-1), 12),
        ("LEFTPADDING",   (0,0),(-1,-1), 16),
        ("RIGHTPADDING",  (0,0),(-1,-1), 16),
    ]))
    els.append(cmd_box)

    # §4 Verification Gates
    els.append(section_num("4", "Verification Gates"))
    gdata = []
    for key, gate_name, gate_desc in GATE_DISPLAY:
        ok = gates_dict.get(key, False)
        gdata.append([Paragraph(gate_name, ST["gate_name"]),
                      Paragraph(gate_desc, ST["gate_desc"]),
                      pass_badge(ok)])
    log_fname = cfg.get("log_filename", "")
    gdata.append([
        Paragraph("Execution log", ST["meta_label"]),
        Paragraph(f'<font color="#00909c">{log_fname}</font>' if log_fname else "—",
                  ST["tbl_cell"]),
        ""])
    gt = Table(gdata, colWidths=[52*mm, CW - 52*mm - 18*mm, 18*mm])
    gt.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(-1,-1), 10),
        ("RIGHTPADDING",  (0,0),(-1,-1), 8),
        ("TOPPADDING",    (0,0),(-1,-1), 7),
        ("BOTTOMPADDING", (0,0),(-1,-1), 7),
        ("ROWBACKGROUNDS",(0,0),(-1,-2), [WHITE, GRAY_LIGHT]),
        ("LINEBELOW",     (0,0),(-1,-2), 0.3, BORDER),
        ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
        ("BACKGROUND",    (0,-1),(-1,-1), GRAY_LIGHT),
        ("LINEABOVE",     (0,-1),(-1,-1), 0.3, BORDER),
    ]))
    els.append(gt)

    # §5 Out of Scope
    els.append(section_num("5", "Out of Scope"))
    out_items = [
        "Genotype correctness or accuracy",
        "Concordance against known truth sets",
        "Sensitivity, specificity, or stutter performance",
        "Allele calling accuracy or forensic casework suitability",
        "Regulatory compliance or ISO accreditation",
        "Multi-laboratory or multi-dataset reproducibility",
    ]
    content = [Paragraph("This report does not evaluate any of the following:", ST["body"])]
    for item in out_items:
        content.append(Paragraph(
            f'<font color="#9ca3af">–</font>  {item}',
            S("oi", fontSize=8.5, textColor=GRAY, leading=14,
              leftIndent=10, spaceAfter=1)))
    els.append(boxed(content))

    # §6 Output Content Evidence
    els.append(section_num("6", "Output Content Evidence"))
    stats = cfg.get("stats", {})
    total_reads = stats.get("total_reads", 0)
    ev_rows = [
        ("Output file",              stats.get("output_file", "result.vcf.gz")),
        ("Format",                   stats.get("format", "VCF")),
        ("Sequence records",         str(stats.get("rows", "—"))),
        ("Distinct STR loci",        str(stats.get("distinct_str_loci", "—"))),
        ("Total reads",              f"{total_reads:,}" if total_reads else "—"),
        ("Max depth (single locus)", str(stats.get("max_sequence_depth", "—"))),
    ]
    tdata = [[Paragraph(k, ST["meta_label"]),
              Paragraph(v, ST["tbl_cell"])] for k, v in ev_rows]
    evt = Table(tdata, colWidths=[60*mm, CW - 60*mm])
    evt.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(-1,-1), 10),
        ("RIGHTPADDING",  (0,0),(-1,-1), 10),
        ("TOPPADDING",    (0,0),(-1,-1), 5),
        ("BOTTOMPADDING", (0,0),(-1,-1), 5),
        ("ROWBACKGROUNDS",(0,0),(-1,-1), [WHITE, GRAY_LIGHT]),
        ("LINEBELOW",     (0,0),(-1,-2), 0.3, BORDER),
        ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
    ]))
    els.append(evt)

    # §7 Verification Data
    els.append(section_num("7", "Verification Data"))
    ds = cfg.get("dataset", {})
    els.append(Paragraph(
        "This tool does not include its own demo or test data. "
        "STRhub ran the verification using the public reference dataset listed below.",
        ST["body"]))
    els.append(vspace(3))

    ref_genome = ds.get("reference_genome", {})
    ref_assembly = ref_genome.get("assembly", "—") if isinstance(ref_genome, dict) else str(ref_genome)
    src = ds.get("source", "")
    src_display = (src[:60] + "…") if len(src) > 60 else src
    loci_list = cfg.get("loci_list", [])
    loci_val = ("  ·  ".join(loci_list)) if loci_list else "—"
    ds_rows = [
        ("Dataset",     ds.get("name", "—")),
        ("Source",      link(src, src_display) if src else "—"),
        ("License",     ds.get("license", "—")),
        ("Ref. genome", ref_assembly),
        ("Loci tested", loci_val),
    ]
    tdata = [[Paragraph(k, ST["meta_label"]),
              Paragraph(v, S("dv", fontSize=8, textColor=GRAY, leading=13))]
             for k, v in ds_rows]
    dst = Table(tdata, colWidths=[36*mm, CW - 36*mm])
    dst.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "TOP"),
        ("LEFTPADDING",   (0,0),(-1,-1), 10),
        ("RIGHTPADDING",  (0,0),(-1,-1), 10),
        ("TOPPADDING",    (0,0),(-1,-1), 5),
        ("BOTTOMPADDING", (0,0),(-1,-1), 5),
        ("ROWBACKGROUNDS",(0,0),(-1,-1), [WHITE, GRAY_LIGHT]),
        ("LINEBELOW",     (0,0),(-1,-2), 0.3, BORDER),
        ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
    ]))
    els.append(dst)

    # §8 Verification Matrix
    rc = cfg.get("readme_check") or {}
    rc_score = rc.get("score", 0)
    rc_max = rc.get("max", 5)
    matrix_rows = [
        ("PASS", "Reference dataset",          ds.get("name", "—")),
        ("",     f"README check ({rc_score}/{rc_max})",
                 "Advisory — all items present" if rc_score == rc_max else f"{rc_score}/{rc_max} items present"),
        ("",     "Install / environment setup", "Present"),
        ("",     "Run command",                 "Present"),
        ("",     "Expected input format",       "Present"),
        ("",     "Produced output format",      "Present"),
        ("",     "Dependencies / versions",     "Present"),
    ]
    tdata = []
    for tag, label, val in matrix_rows:
        tag_p = Paragraph(
            f'<font color="#00909c"><b>{tag}</b></font>' if tag else "",
            ST["tbl_cell"])
        tdata.append([tag_p, Paragraph(label, ST["tbl_cell"]),
                      Paragraph(val, ST["tbl_cell"])])
    C2 = CW * 0.52
    mt = Table(tdata, colWidths=[16*mm, C2, CW - 16*mm - C2])
    mt.setStyle(TableStyle([
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("LEFTPADDING",   (0,0),(-1,-1), 10),
        ("RIGHTPADDING",  (0,0),(-1,-1), 10),
        ("TOPPADDING",    (0,0),(-1,-1), 5),
        ("BOTTOMPADDING", (0,0),(-1,-1), 5),
        ("ROWBACKGROUNDS",(0,0),(-1,-1), [WHITE, GRAY_LIGHT]),
        ("LINEBELOW",     (0,0),(-1,-2), 0.3, BORDER),
        ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
        ("SPAN",          (0,0),(0,-1)),
        ("VALIGN",        (0,0),(0,-1), "TOP"),
    ]))
    els.append(keep_section(section_num("8", "Verification Matrix"), mt))

    # §9 Limitations
    els.append(section_num("9", "Limitations"))
    lim_items = [
        "Single reference dataset per input type",
        "Single containerized environment (Docker / ubuntu-22.04)",
        "No truth-set comparison or ground-truth genotypes",
        "No accuracy or concordance assessment",
        "No forensic validation of results",
        "Short-read limitations apply (very long STR alleles may not span reads)",
    ]
    lim = [Paragraph(
        f'<font color="#9ca3af">–</font>  {item}',
        S("li", fontSize=8.5, textColor=GRAY, leading=14,
          leftIndent=10, spaceAfter=1)) for item in lim_items]
    els.append(boxed(lim))

    # §10 Disclaimers
    els.append(section_num("10", "Scope and Disclaimers"))
    disc = (
        "Executed end-to-end in the stated environment with output in the expected format. "
        "Concerns reproducible execution only; no claim of accuracy, casework fitness, "
        "or regulatory validation.<br/><br/>"
        "Each result is a dated snapshot, verified on the tool's public repository at a "
        "pinned commit. STRhub does not store tool source code."
    )
    els.append(boxed([Paragraph(disc, ST["body"])]))

    # §11 Conclusion
    top_loci = stats.get("top_loci_by_depth", [])
    n_loci = stats.get("distinct_str_loci", 0)
    max_depth = stats.get("max_sequence_depth", 0)
    deepest_locus = top_loci[0][0] if top_loci else "—"

    conclusion_items = [
        ("Runs end-to-end",
         f"{cfg['tool_display']} installs and executes without error in a clean "
         f"ubuntu-22.04 environment at the pinned commit. All {n_pass} verification "
         "gates were passed."),
        ("Produces valid output",
         f"The tool generated a structurally valid VCF file with genotype "
         f"calls across {n_loci} target forensic STR loci, with a "
         f"maximum read depth of {max_depth} at {deepest_locus}."),
        ("No bundled demo data",
         f"{cfg['tool_name']} does not include its own test or demo dataset. "
         "STRhub Verified supplied the GIAB NA12878 300× dataset "
         "(GRCh38) as the reference input for this verification run. "
         "Users replicating this result should use the same or equivalent "
         "publicly available reference material."),
        ("Reproducibility statement",
         "The exact command reported in Section 3, executed at the pinned "
         "commit in the described environment, is sufficient to reproduce "
         "this verification result independently."),
    ]
    con_content = []
    for title, body in conclusion_items:
        con_content.append(Paragraph(
            f'<font color="#00909c">◆</font>  <b>{title}</b>',
            S("ct2", fontSize=9, textColor=INK, leading=14,
              fontName="Helvetica-Bold", spaceAfter=2)))
        con_content.append(Paragraph(body,
            S("cb2", fontSize=8.5, textColor=GRAY, leading=13,
              leftIndent=14, spaceAfter=8)))
    con_box = Table([[con_content]], colWidths=[CW])
    con_box.setStyle(TableStyle([
        ("BACKGROUND",    (0,0),(-1,-1), TEAL_LIGHT),
        ("BOX",           (0,0),(-1,-1), 0.8, TEAL_MID),
        ("TOPPADDING",    (0,0),(-1,-1), 14),
        ("BOTTOMPADDING", (0,0),(-1,-1), 14),
        ("LEFTPADDING",   (0,0),(-1,-1), 16),
        ("RIGHTPADDING",  (0,0),(-1,-1), 16),
    ]))
    els.append(keep_section(section_num("11", "Conclusion"), con_box))
    return els

# ── Appendix ──────────────────────────────────────────────────────────────────
def build_appendix(cfg):
    loci_data = cfg.get("loci_with_depth", [])
    if not loci_data:
        return []

    els = []
    els.append(build_header_inner(cfg))
    els.append(HR(TEAL, thickness=1.2, spaceB=4, spaceA=8))
    els.append(Paragraph("Appendix — Detected Markers with Read Depth",
                          ST["appendix_title"]))
    els.append(Paragraph(
        f"{cfg['tool_display']} · verified {cfg['ver_date']}",
        S("as2", fontSize=8, textColor=GRAY, leading=12, spaceAfter=10)))

    MAX = max((d for _, d in loci_data), default=1) or 1

    # Two-column layout: split loci in half so all fit on one page.
    col_gap = 5 * mm
    col_w   = (CW - col_gap) / 2
    locus_w = 26 * mm
    depth_w = 20 * mm
    bar_w   = col_w - locus_w - depth_w
    half    = (len(loci_data) + 1) // 2        # ceil — left col gets the extra row
    chunks  = [loci_data[:half], loci_data[half:]]

    def _loci_table(subset):
        header = [Paragraph("LOCUS", ST["tbl_header"]),
                  Paragraph("READ DEPTH", ST["tbl_header"]),
                  Paragraph("", ST["tbl_header"])]
        tdata = [header]
        for locus, depth in subset:
            pct    = depth / MAX
            bars   = "█" * int(pct * 16)      # narrower bars for half-width column
            bar_col = "#00909c" if depth > 0 else "#ef4444"
            dep_str = str(depth) if depth > 0 else "0"
            dep_style = ST["tbl_cell"] if depth > 0 else \
                S("ze", fontSize=8.5, textColor=RED_SOFT, leading=12)
            tdata.append([
                Paragraph(locus, ST["locus_name"]),
                Paragraph(dep_str, dep_style),
                Paragraph(f'<font color="{bar_col}" size="6">{bars}</font>',
                          S("bar", fontSize=6, leading=10)),
            ])

        styles = [
            ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
            ("LEFTPADDING",   (0,0),(-1,-1), 8),
            ("RIGHTPADDING",  (0,0),(-1,-1), 6),
            ("TOPPADDING",    (0,0),(-1,-1), 4),
            ("BOTTOMPADDING", (0,0),(-1,-1), 4),
            ("BACKGROUND",    (0,0),(-1,0),  GRAY_LIGHT),
            ("ROWBACKGROUNDS",(0,1),(-1,-1), [WHITE, GRAY_LIGHT]),
            ("LINEBELOW",     (0,0),(-1,0),  0.8, BORDER),
            ("LINEBELOW",     (0,1),(-1,-2), 0.3, BORDER),
            ("BOX",           (0,0),(-1,-1), 0.5, BORDER),
        ]
        for i, (_, depth) in enumerate(subset):
            if depth == 0:
                styles.append(("BACKGROUND", (0, i+1), (-1, i+1),
                                colors.HexColor("#fef2f2")))
        tbl = Table(tdata, colWidths=[locus_w, depth_w, bar_w])
        tbl.setStyle(TableStyle(styles))
        return tbl

    left_tbl  = _loci_table(chunks[0])
    right_tbl = _loci_table(chunks[1]) if chunks[1] else Spacer(col_w, 1)

    outer = Table([[left_tbl, right_tbl]], colWidths=[col_w, col_w],
                  hAlign="LEFT", spaceAfter=0)
    outer.setStyle(TableStyle([
        ("VALIGN",       (0,0),(-1,-1), "TOP"),
        ("LEFTPADDING",  (0,0),(-1,-1), 0),
        ("RIGHTPADDING", (0,0),(0,-1),  col_gap),
        ("RIGHTPADDING", (1,0),(1,-1),  0),
        ("TOPPADDING",   (0,0),(-1,-1), 0),
        ("BOTTOMPADDING",(0,0),(-1,-1), 0),
    ]))
    els.append(outer)
    return els

# ── Config loader ─────────────────────────────────────────────────────────────
def _format_cmd(raw_cmd: str) -> list[str]:
    parts = raw_cmd.split()
    if not parts:
        return ["# (no command)"]
    lines = [f"$ {parts[0]} \\"]
    for i, p in enumerate(parts[1:], 1):
        suffix = "" if i == len(parts) - 1 else " \\"
        lines.append(f"    {p}{suffix}")
    return lines


def load_config(manifest_path: str, datasets_path: str | None = None) -> dict:
    mpath = pathlib.Path(manifest_path)
    m = yaml.safe_load(mpath.read_text())

    slug = m.get("report", {}).get("slug")
    if not slug:
        slug = re.sub(r"[^a-z0-9]+", "-", m["tool"]["name"].lower()).strip("-")

    # Report JSON — always next to reports/ relative to CWD (how CI calls us)
    report_path = pathlib.Path("reports") / f"{slug}.json"
    report: dict = {}
    if report_path.exists():
        report = json.loads(report_path.read_text())

    # Dates
    generated = report.get("generated", "")
    gen_date = generated[:10] if generated else dt.date.today().isoformat()
    ver_time = (generated[11:19] + " UTC") if len(generated) > 19 else ""

    # Tool identity
    tool_name_raw = m["tool"]["name"]
    tool_name = tool_name_raw.title() if tool_name_raw == tool_name_raw.lower() else tool_name_raw
    tool_version = m["tool"]["version"]
    tool_display = f"{tool_name} {tool_version}"

    # Source
    repo_url = m["source"]["repo"]
    commit = report.get("source", {}).get("ref_resolved") or m["source"].get("ref", "")
    commit_url = f"{repo_url}/commit/{commit}"

    # Gates
    gates_raw = report.get("gates", {})
    gates = {key: gates_raw.get(key, False) for key, _, _ in GATE_DISPLAY}
    level = report.get("level", "none")

    # Run command
    raw_cmd = m.get("run", {}).get("cmd", "")
    env_note = f"# Environment: {(m.get('environment', {}).get('os') or ['ubuntu-22.04'])[0]}  ·  {tool_display}  ·  commit {commit[:7]}"
    cmd_lines = [env_note, ""] + _format_cmd(raw_cmd)

    # Dataset
    input_type = m.get("inputs", {}).get("type", "")
    ds_file = pathlib.Path(datasets_path) if datasets_path else pathlib.Path("datasets/index.json")
    dataset: dict = {}
    if ds_file.exists():
        ds_index = json.loads(ds_file.read_text())
        dataset = ds_index.get("datasets", {}).get(input_type, {})

    # Stats from content_detail
    stats: dict = {}
    outputs = report.get("content_detail", {}).get("outputs", [])
    if outputs and isinstance(outputs[0], dict):
        raw_stats = outputs[0].get("stats", {})
        stats = {**raw_stats,
                 "output_file": outputs[0].get("resolved", "result.vcf.gz"),
                 "format": "VCF"}

    # Loci (sorted by depth desc — top_loci_by_depth is already most_common())
    loci_with_depth = [(l, d) for l, d in stats.get("top_loci_by_depth", [])]

    return {
        "slug":           slug,
        "tool_name":      tool_name,
        "tool_version":   tool_version,
        "tool_display":   tool_display,
        "gen_date":       gen_date,
        "ver_date":       gen_date,
        "ver_time":       ver_time,
        "repo_url":       repo_url,
        "commit":         commit,
        "commit_url":     commit_url,
        "permalink":      f"https://strhub.app/verified/{slug}",
        "ci_run":         report.get("ci_run", ""),
        "gates":          gates,
        "level":          level,
        "cmd_lines":      cmd_lines,
        "container_os":   (m.get("environment", {}).get("os") or ["ubuntu-22.04"])[0],
        "panel":          PANEL_MAP.get(input_type, input_type or "STR"),
        "stats":          stats,
        "loci_with_depth":loci_with_depth,
        "loci_list":      stats.get("str_loci", []),
        "dataset":        dataset,
        "readme_check":   report.get("readme_check") or {},
        "log_filename":   (report.get("logs") or {}).get("external")
                          or (report.get("logs") or {}).get("own", ""),
    }

# ── Entry point ───────────────────────────────────────────────────────────────
def main() -> int:
    ap = argparse.ArgumentParser(
        description="Generate a STRhub Verified PDF from a completed CI run.")
    ap.add_argument("--manifest", required=True,
                    help="Path to tools/<slug>/manifest.yml")
    ap.add_argument("--datasets",
                    help="Path to datasets/index.json (auto-detected if omitted)")
    ap.add_argument("--out",
                    help="Output PDF path (default: reports/<slug>.pdf)")
    args = ap.parse_args()

    cfg = load_config(args.manifest, args.datasets)

    out_path = args.out or f"reports/{cfg['slug']}.pdf"
    pathlib.Path(out_path).parent.mkdir(parents=True, exist_ok=True)

    doc = SimpleDocTemplate(
        out_path, pagesize=A4,
        leftMargin=ML, rightMargin=MR,
        topMargin=MT, bottomMargin=MB + 8*mm,
        title=f"STRhub Verified — {cfg['tool_display']}",
        author="STRhub · strhub.app",
        subject="Technical Reproducibility Validation Report",
    )
    story: list = []
    story += build_cover(cfg)
    story.append(PageBreak())
    story += build_body(cfg)
    appendix = build_appendix(cfg)
    if appendix:
        story.append(PageBreak())
        story += appendix

    doc.build(story, canvasmaker=_make_canvas_class(cfg))
    print(f"✓ {out_path}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
